const texto = $input.item.json.mensagem_original || "";

function limparMarkdown(str) {
  return str
    .replace(/^#{1,6}\s+/gm, '')
    .replace(/\*\*(.+?)\*\*/g, '$1')
    .replace(/__(.+?)__/g, '$1')
    .replace(/\*(.+?)\*/g, '$1')
    .replace(/_(.+?)_/g, '$1')
    .replace(/~~(.+?)~~/g, '$1')
    .replace(/```[\s\S]*?```/g, '')
    .replace(/`(.+?)`/g, '$1')
    .replace(/\[([^\]]+)\]\([^)]+\)/g, '$1')
    .replace(/!\[([^\]]*)\]\([^)]+\)/g, '')
    .replace(/^>\s+/gm, '')
    .replace(/^[-*_]{3,}\s*$/gm, '')
    .replace(/^[\s]*[-*+]\s+/gm, '• ')
    .replace(/^[\s]*\d+\.\s+/gm, '')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

const textoLimpo = limparMarkdown(texto);

if (textoLimpo.length <= 150) {
  return {
    json: {
      output: {
        messages: [textoLimpo]
      }
    }
  };
}

const paragrafos = textoLimpo.split(/\n\n+/).map(p => p.trim()).filter(p => p);

if (paragrafos.length <= 1) {
  const sentencas = textoLimpo.split(/(?<=[.!?])\s+/).filter(s => s.trim());
  let mensagens = [];
  let atual = "";

  for (const sentenca of sentencas) {
    if ((atual + " " + sentenca).trim().length <= 300) {
      atual = (atual + " " + sentenca).trim();
    } else {
      if (atual) mensagens.push(atual);
      atual = sentenca;
    }
  }
  if (atual) mensagens.push(atual);

  return {
    json: {
      output: {
        messages: mensagens.length > 0 ? mensagens : [textoLimpo]
      }
    }
  };
}

let mensagens;
if (paragrafos.length <= 4) {
  mensagens = paragrafos;
} else {
  mensagens = [
    paragrafos[0],
    paragrafos[1],
    paragrafos[2],
    paragrafos.slice(3).join("\n\n")
  ];
}

return {
  json: {
    output: {
      messages: mensagens
    }
  }
};

